-- Seed: בית תאילנדי (Thai House), Bograshov 8, Tel Aviv — dinner menu.
--
-- Session-7 hand-seed (build-plan §4B grounded contract). Transcribed verbatim
-- from the restaurant's OWN site dinner menu:
--   https://www.thai-house.co.il/menus/תפריט-ערב/
-- TRANSCRIBE-ONLY: every dish below appears on that page. source='claudecode',
-- real source_url, verified=false (human spot-check still pending). The DB
-- menus_provenance CHECK requires the source_url, satisfied here.
--
-- Self-contained + idempotent: upserts the restaurant (survives a truncate),
-- deletes this restaurant's existing menu, re-inserts menu + dishes. Dishes with
-- multiple printed prices use the first (base) price. fetched_at defaults to
-- now() so the app serves it immediately (matches the other Session-4 seeds).
--
-- Estimates are filled separately by the deployed estimate-dishes function
-- (Haiku) — not invented here.

values ('ChIJP841K3xMHRURebdaloB-MZA', 'בית תאילנדי', 'בוגרשוב 8, תל אביב-יפו, ישראל',
        'http://www.thai-house.co.il/', 32.0775921, 34.7682231)
on conflict (place_id) do update
  set name = excluded.name, address = excluded.address, website = excluded.website,
      lat = excluded.lat, lng = excluded.lng;

do $do$
declare rid uuid; mid uuid;
begin
  select id into rid from restaurants where place_id = 'ChIJP841K3xMHRURebdaloB-MZA';
  delete from menus where restaurant_id = rid;
    values (rid, 'claudecode', null,
      'https://www.thai-house.co.il/menus/%d7%aa%d7%a4%d7%a8%d7%99%d7%98-%d7%a2%d7%a8%d7%91/', false)
    returning id into mid;


  raise notice 'Thai House menu % seeded with % dishes', mid, (select count(*) from dishes where menu_id = mid);
end $do$;
